COMMIT;

-- ----------------------------
-- Table structure for wp_articles
-- ----------------------------
DROP TABLE IF EXISTS `wp_articles`;
CREATE TABLE `wp_articles` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '記事ID',
  `module_id` int unsigned DEFAULT NULL COMMENT '所属モジュール',
  `title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '記事タイトル',
  `slug` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'URLスラッグ',
  `excerpt` text COLLATE utf8mb4_unicode_ci COMMENT '抜粋文',
  `content` longtext COLLATE utf8mb4_unicode_ci COMMENT '本文（HTML）',
  `cover_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'カバーイラスト種別',
  `scene` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'シーン（class, blackboard...）',
  `difficulty` tinyint NOT NULL DEFAULT '1' COMMENT '難易度: 1=初級 2=中級 3=上級',
  `reading_min` int NOT NULL DEFAULT '0' COMMENT '読了目安（分）',
  `view_count` int unsigned NOT NULL DEFAULT '0' COMMENT '閲覧数',
  `author_id` bigint unsigned DEFAULT NULL COMMENT '著者ID（wp_authors）',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft' COMMENT 'draft/published/archived',
  `published_at` datetime DEFAULT NULL COMMENT '公開日時',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_slug` (`slug`),
  KEY `idx_module` (`module_id`),
  KEY `idx_difficulty` (`difficulty`),
  KEY `idx_status` (`status`),
  KEY `idx_published` (`published_at`),
  KEY `idx_views` (`view_count`),
  FULLTEXT KEY `ft_search` (`title`,`excerpt`,`content`),
  CONSTRAINT `fk_article_module` FOREIGN KEY (`module_id`) REFERENCES `wp_modules` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='学習記事';

-- ----------------------------
-- Records of wp_articles
-- ----------------------------
BEGIN;
COMMIT;

