-- ----------------------------
-- Table structure for wp_modules
-- ----------------------------
DROP TABLE IF EXISTS `wp_modules`;
CREATE TABLE `wp_modules` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'モジュールID',
  `code` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'モジュールコード（FI, CO, MM...）',
  `name_ja` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '日本語名（財務会計、管理会計...）',
  `name_en` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '英語名',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT 'モジュール説明',
  `slug` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'URL用スラッグ',
  `color` varchar(7) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'テーマカラー（#2f6d44）',
  `bg_color` varchar(7) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '背景カラー（#d8ead9）',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '表示順',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '1=公開 0=非公開',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_code` (`code`),
  UNIQUE KEY `uk_slug` (`slug`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='SAPモジュールマスタ';

