INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (74, 1, '2026-06-06 14:52:25', '2026-06-06 14:52:25', '<h2>はじめに</h2>\n<p>afdsfsdfについて解説します。SAPを学ぶ上で重要なテーマです。パンダ先生がわかりやすく説明します。</p>\n\n<div class=\"dialog\"><div class=\"av\">[panda]</div><div class=\"bubble\"><span class=\"who\">パンダ先生</span>afdsfsdfは、現場で必ず役立つ知識です。しっかりマスターしましょう！</div></div>\n\n<h2>SAPにおける基礎知識</h2>\n<p>SAPを理解するには、まず基本から押さえることが大切です。</p>\n\n<div class=\"dialog student\"><div class=\"av\">[taro]</div><div class=\"bubble\"><span class=\"who\">たろうくん</span>なるほど！でも実際にはどう使えばいいんですか？</div></div>\n\n<div class=\"dialog\"><div class=\"av\">[panda]</div><div class=\"bubble\"><span class=\"who\">パンダ先生</span>良い質問だね！実際の業務フローに沿って説明するよ。</div></div>\n\n<h2>まとめ</h2>\n<p>SAPの基礎をしっかり押さえましょう。パンダ先生と一緒に、一歩ずつ進めていきましょう！</p>', 'afdsfsdf', '', 'publish', 'open', 'open', '', 'afdsfsdf', '', '', '2026-06-07 09:57:04', '2026-06-07 09:57:04', '', 0, 'http://localhost/?p=74', 0, 'post', '', 0);
