INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (79, 1, '2026-06-07 04:04:31', '2026-06-07 04:04:31', '<h2>はじめに</h2>\n<p>【完全保存版】仕訳のしくみ — 借方・貸方を一発で覚えるについて解説します。財務会計を学ぶ上で重要なテーマです。パンダ先生がわかりやすく説明します。</p>\n\n<div class=\"dialog\"><div class=\"av\">[panda]</div><div class=\"bubble\"><span class=\"who\">パンダ先生</span>【完全保存版】仕訳のしくみ — 借方・貸方を一発で覚えるは、現場で必ず役立つ知識です。しっかりマスターしましょう！</div></div>\n\n<h2>財務会計における基礎知識</h2>\n<p>財務会計を理解するには、まず基本から押さえることが大切です。</p>\n\n<div class=\"dialog student\"><div class=\"av\">[taro]</div><div class=\"bubble\"><span class=\"who\">たろうくん</span>なるほど！でも実際にはどう使えばいいんですか？</div></div>\n\n<div class=\"dialog\"><div class=\"av\">[panda]</div><div class=\"bubble\"><span class=\"who\">パンダ先生</span>良い質問だね！実際の業務フローに沿って説明するよ。</div></div>\n\n<h2>まとめ</h2>\n<p>財務会計の基礎をしっかり押さえましょう。パンダ先生と一緒に、一歩ずつ進めていきましょう！</p>', '【完全保存版】仕訳のしくみ — 借方・貸方を一発で覚える', '簿記の本を読んでも頭に入らない…そんなあなたへ。覚えるべきは「左右がイコール」というたった一つのルールだけ。', 'publish', 'open', 'open', '', '%e3%80%90%e5%ae%8c%e5%85%a8%e4%bf%9d%e5%ad%98%e7%89%88%e3%80%91%e4%bb%95%e8%a8%b3%e3%81%ae%e3%81%97%e3%81%8f%e3%81%bf-%e5%80%9f%e6%96%b9%e3%83%bb%e8%b2%b8%e6%96%b9%e3%82%92%e4%b8%80%e7%99%ba', '', '', '2026-06-07 09:57:04', '2026-06-07 09:57:04', '', 0, 'http://localhost/%e3%80%90%e5%ae%8c%e5%85%a8%e4%bf%9d%e5%ad%98%e7%89%88%e3%80%91%e4%bb%95%e8%a8%b3%e3%81%ae%e3%81%97%e3%81%8f%e3%81%bf-%e5%80%9f%e6%96%b9%e3%83%bb%e8%b2%b8%e6%96%b9%e3%82%92%e4%b8%80%e7%99%ba/', 0, 'post', '', 0);
