INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (172, 1, '2026-06-07 04:21:21', '2026-06-07 04:21:21', '<p>会計伝票の基本 — FB50 から学ぶ伝票入力のすべて</p>\n<p>SAP FI の学習コンテンツです。パンダ先生がわかりやすく解説します。</p>\n<h2>はじめに</h2>\n<p>この記事では、「会計伝票の基本 — FB50 から学ぶ伝票入力のすべて」について詳しく解説します。実務ですぐに使える知識を身につけましょう。</p>\n<h2>ポイント</h2>\n<ul>\n<li>基礎的な概念の理解</li>\n<li>SAP システム上の具体的な操作方法</li>\n<li>実践的な設定・カスタマイズのコツ</li>\n</ul>\n<h2>まとめ</h2>\n<p>パンダ先生と一緒に、一歩ずつ SAP をマスターしていきましょう。</p>\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', '会計伝票の基本 — FB50 から学ぶ伝票入力のすべて', '会計伝票の基本 — FB50 から学ぶ伝票入力のすべて。SAP FI を学ぶための実践的な記事です。', 'inherit', 'closed', 'closed', '', '94-autosave-v1', '', '', '2026-06-07 04:21:21', '2026-06-07 04:21:21', '', 94, 'http://localhost/?p=172', 0, 'revision', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES (173, 0, '2026-06-07 04:25:31', '2026-06-07 04:25:31', '<h2>はじめに</h2>\n<p>S/4HANA コンサルタントになるにはについて解説します。S/4HANAを学ぶ上で重要なテーマです。パンダ先生がわかりやすく説明します。</p>\n\n<h2>S/4HANAにおける位置づけ</h2>\n<p>S/4HANAを理解するには、まず基本から押さえることが大切です。このトピックは実務で頻繁に登場し、SAPコンサルタントとして必ず押さえておくべき内容です。</p>\n<p>SAPシステム上での具体的な操作方法や設定手順を、実際の画面イメージとともに解説します。</p>\n\n<div class=\"dialog\"><div class=\"av\">P</div><div class=\"bubble\"><span class=\"who\">パンダ先生</span>S/4HANA コンサルタントになるにはは、現場で必ず役立つ知識です。しっかりマスターしましょう！</div></div>\n\n<h2>実践的なポイント</h2>\n<p>以下のポイントを押さえておくと、実務でスムーズに対応できます。</p>\n<ul>\n<li><strong>基本原則を理解する</strong> — なぜこの機能が必要か、背景から理解しましょう。</li>\n<li><strong>トランザクションコードを覚える</strong> — よく使うものから少しずつ。</li>\n<li><strong>エラーケースを知る</strong> — 実際の現場で起こりがちなミスを事前に把握。</li>\n</ul>', 'S/4HANA コンサルタントになるには', 'S/4HANA コンサルタントになるには。SAP S4 を学ぶための実践的な記事です。', 'inherit', 'closed', 'closed', '', '171-revision-v1', '', '', '2026-06-07 04:25:31', '2026-06-07 04:25:31', '', 171, 'http://localhost/?p=173', 0, 'revision', '', 0);
